module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

localparam IDLE = s0;
localparam PULSE_START = s1;
localparam PULSE_END = s2;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        data_out <= 0;
    end else begin
        case (state)
            IDLE: begin
                if (data_in == 1'b1) begin
                    state <= PULSE_START;
                end else begin
                    data_out <= 0;
                end
            end
            PULSE_START: begin
                if (data_in == 1'b0) begin
                    state <= PULSE_END;
                end else begin
                    state <= PULSE_START;
                end
            end
            PULSE_END: begin
                if (data_in == 1'b1) begin
                    state <= PULSE_END;
                end else begin
                    state <= IDLE;
                    data_out <= 1;
                end
            end
        endcase
    end
end

endmodule
